     1→// vorc_commit.rs - Core commit infrastructure for VOK
     2→//
     3→// Provides atomic commit workflow: lock, stage, guard, commit.
     4→// Used by vvc-commit and JJ commands for consistent commit handling.
     5→//
     6→// Usage: vvx commit [--prefix <str>] [--message <str>] [--allow-empty] [--no-stage]
     7→//
     8→// Exit codes:
     9→//   0 - Success (commit hash printed to stdout)
    10→//   1 - Failure (lock held, guard failed, claude failed, commit failed)
    11→
    12→use clap::Args;
    13→use std::process::Command;
    14→
    15→/// Lock reference path for commit operations
    16→const LOCK_REF: &str = "refs/vvg/locks/vvx";
    17→
    18→/// Default size limits (match vvg_git.sh constants)
    19→const SIZE_LIMIT: u64 = 50000;
    20→const WARN_LIMIT: u64 = 30000;
    21→
    22→#[derive(Args, Debug)]
    23→pub struct CommitArgs {
    24→    /// Prefix string to prepend to commit message (e.g., "[jj:BRAND][F00/silks]")
    25→    #[arg(long)]
    26→    pub prefix: Option<String>,
    27→
    28→    /// Commit message; if absent, invoke claude to generate from diff
    29→    #[arg(short, long)]
    30→    pub message: Option<String>,
    31→
    32→    /// Allow empty commits (for chalk markers)
    33→    #[arg(long)]
    34→    pub allow_empty: bool,
    35→
    36→    /// Skip 'git add -u' (respect pre-staged files)
    37→    #[arg(long)]
    38→    pub no_stage: bool,
    39→}
    40→
    41→/// Acquire the commit lock using git update-ref
    42→/// Returns Ok(()) on success, Err(message) if lock already held
    43→fn acquire_lock() -> Result<(), String> {
    44→    // Get current HEAD as lock value
    45→    let head_output = Command::new("git")
    46→        .args(["rev-parse", "HEAD"])
    47→        .output()
    48→        .map_err(|e| format!("Failed to run git rev-parse: {}", e))?;
    49→
    50→    let lock_value = if head_output.status.success() {
    51→        String::from_utf8_lossy(&head_output.stdout).trim().to_string()
    52→    } else {
    53→        // No HEAD yet (empty repo) - use null SHA
    54→        "0000000000000000000000000000000000000000".to_string()
    55→    };
    56→
    57→    // Try to create the ref - empty third arg means "only create if ref doesn't exist"
    58→    let result = Command::new("git")
    59→        .args(["update-ref", LOCK_REF, &lock_value, ""])
    60→        .output()
    61→        .map_err(|e| format!("Failed to run git update-ref: {}", e))?;
    62→
    63→    if result.status.success() {
    64→        eprintln!("commit: lock acquired");
    65→        Ok(())
    66→    } else {
    67→        Err("Another commit in progress - lock held".to_string())
    68→    }
    69→}
    70→
    71→/// Release the commit lock
    72→fn release_lock() {
    73→    let _ = Command::new("git")
    74→        .args(["update-ref", "-d", LOCK_REF])
    75→        .output();
    76→    eprintln!("commit: lock released");
    77→}
    78→
    79→/// Stage tracked file changes with 'git add -u'
    80→fn stage_changes() -> Result<(), String> {
    81→    let result = Command::new("git")
    82→        .args(["add", "-u"])
    83→        .output()
    84→        .map_err(|e| format!("Failed to run git add: {}", e))?;
    85→
    86→    if result.status.success() {
    87→        eprintln!("commit: staged tracked changes");
    88→        Ok(())
    89→    } else {
    90→        Err(format!(
    91→            "git add -u failed: {}",
    92→            String::from_utf8_lossy(&result.stderr)
    93→        ))
    94→    }
    95→}
    96→
    97→/// Check if there are staged changes
    98→fn has_staged_changes() -> Result<bool, String> {
    99→    let result = Command::new("git")
   100→        .args(["diff", "--cached", "--quiet"])
   101→        .output()
   102→        .map_err(|e| format!("Failed to run git diff: {}", e))?;
   103→
   104→    // Exit code 0 = no differences (nothing staged)
   105→    // Exit code 1 = differences exist (something staged)
   106→    Ok(!result.status.success())
   107→}
   108→
   109→/// Run size guard check on staged content
   110→/// Returns Ok(()) if under limit, Err if over limit
   111→fn run_guard() -> Result<(), String> {
   112→    // Reuse the guard logic from vorg_guard
   113→    // We import it as a module in vorm_main, so call it directly
   114→    let args = crate::vorg_guard::GuardArgs {
   115→        limit: SIZE_LIMIT,
   116→        warn: WARN_LIMIT,
   117→    };
   118→
   119→    let result = crate::vorg_guard::run(args);
   120→
   121→    match result {
   122→        0 => Ok(()),
   123→        1 => Err("Staged content exceeds size limit".to_string()),
   124→        2 => {
   125→            eprintln!("commit: WARNING - staged content near size limit");
   126→            Ok(())
   127→        }
   128→        _ => Err(format!("Guard returned unexpected code: {}", result)),
   129→    }
   130→}
   131→
   132→/// Get the staged diff for commit message generation
   133→fn get_staged_diff() -> Result<String, String> {
   134→    let output = Command::new("git")
   135→        .args(["diff", "--cached"])
   136→        .output()
